#!/usr/bin/env python3
"""Generate a simple Markdown report from a JSON data file.

The script loads a JSON file (object or array) and produces a human-readable
Markdown report, then prints it to stdout.

Meta:
  created_at: 2026-04-01T09:10:00+08:00
  author: metaclaw_agent
  status: done
"""

from __future__ import annotations

import argparse
import json
import os
import sys
from datetime import datetime, timezone
from typing import Any, Dict, Iterable, List, Mapping, Sequence, Tuple


class ReportError(Exception):
    """Base error for report generation."""


def load_json(path: str) -> Any:
    """Load JSON from path with clearer error messages."""
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except FileNotFoundError as e:
        raise ReportError(f"JSON file not found: {path}") from e
    except PermissionError as e:
        raise ReportError(f"No permission to read JSON file: {path}") from e
    except json.JSONDecodeError as e:
        raise ReportError(
            f"Invalid JSON in {path} (line {e.lineno}, col {e.colno}): {e.msg}"
        ) from e


def _md_escape(text: str) -> str:
    # Minimal escaping for Markdown tables.
    return text.replace("|", "\\|").replace("\n", " ")


def _summarize(data: Any) -> Dict[str, Any]:
    """Compute lightweight summary stats for the input JSON."""
    summary: Dict[str, Any] = {
        "type": type(data).__name__,
    }

    if isinstance(data, Mapping):
        summary["keys"] = len(data)
    elif isinstance(data, Sequence) and not isinstance(data, (str, bytes, bytearray)):
        summary["items"] = len(data)

        # If it's a list of dicts, compute common keys.
        if data and all(isinstance(x, Mapping) for x in data):
            key_counts: Dict[str, int] = {}
            for row in data:  # type: ignore[assignment]
                for k in row.keys():
                    key_counts[str(k)] = key_counts.get(str(k), 0) + 1
            # Top keys by frequency
            summary["top_keys"] = sorted(key_counts.items(), key=lambda kv: (-kv[1], kv[0]))[:10]
    return summary


def generate_markdown(data: Any, *, title: str = "JSON Report") -> str:
    """Generate a Markdown report string for a JSON-serializable structure."""
    generated_at = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
    summary = _summarize(data)

    lines: List[str] = []
    lines.append(f"# {title}")
    lines.append("")
    lines.append(f"- **Generated at (UTC):** {generated_at}")
    lines.append(f"- **Data type:** `{summary.get('type')}`")
    if "keys" in summary:
        lines.append(f"- **Top-level keys:** {summary['keys']}")
    if "items" in summary:
        lines.append(f"- **Top-level items:** {summary['items']}")
    lines.append("")

    # Render based on type.
    if isinstance(data, Mapping):
        lines.append("## Top-level object")
        lines.append("")
        lines.append("| Key | Type | Preview |");
        lines.append("|---|---|---|")
        for k in sorted(data.keys(), key=lambda x: str(x)):
            v = data[k]
            v_type = type(v).__name__
            preview = json.dumps(v, ensure_ascii=False) if not isinstance(v, (str, bytes, bytearray)) else str(v)
            if len(preview) > 120:
                preview = preview[:117] + "..."
            lines.append(f"| `{_md_escape(str(k))}` | `{v_type}` | {_md_escape(preview)} |")

    elif isinstance(data, Sequence) and not isinstance(data, (str, bytes, bytearray)):
        lines.append("## Top-level array")
        lines.append("")

        if data and all(isinstance(x, Mapping) for x in data):
            rows: List[Mapping[str, Any]] = list(data)  # type: ignore[assignment]
            lines.append("### Sample rows")
            lines.append("")
            # Choose a stable set of columns: union of first N rows keys.
            cols: List[str] = []
            for row in rows[:20]:
                for k in row.keys():
                    sk = str(k)
                    if sk not in cols:
                        cols.append(sk)
                if len(cols) >= 10:
                    break
            cols = cols[:10]

            if cols:
                lines.append("| " + " | ".join(f"`{_md_escape(c)}`" for c in cols) + " |")
                lines.append("|" + "|".join(["---"] * len(cols)) + "|")
                for row in rows[:10]:
                    vals: List[str] = []
                    for c in cols:
                        v = row.get(c)
                        if v is None:
                            vals.append("")
                        elif isinstance(v, (str, int, float, bool)):
                            vals.append(_md_escape(str(v)))
                        else:
                            pv = json.dumps(v, ensure_ascii=False)
                            if len(pv) > 60:
                                pv = pv[:57] + "..."
                            vals.append(_md_escape(pv))
                    lines.append("| " + " | ".join(vals) + " |")

            # Key frequency section
            if isinstance(summary.get("top_keys"), list):
                lines.append("")
                lines.append("### Most common keys")
                lines.append("")
                lines.append("| Key | Count |");
                lines.append("|---|---:|")
                for k, cnt in summary["top_keys"]:  # type: ignore[index]
                    lines.append(f"| `{_md_escape(str(k))}` | {cnt} |")
        else:
            # Generic list preview
            lines.append("### Preview")
            lines.append("")
            for i, item in enumerate(list(data)[:10], start=1):
                lines.append(f"- {i}. `{type(item).__name__}`: {json.dumps(item, ensure_ascii=False)[:200]}")

    else:
        lines.append("## Value")
        lines.append("")
        lines.append("```")
        lines.append(str(data))
        lines.append("```")

    lines.append("")
    return "\n".join(lines)


def main(argv: Iterable[str] | None = None) -> int:
    ap = argparse.ArgumentParser(description="Generate a Markdown report from a JSON file.")
    ap.add_argument("json_path", help="Path to JSON data file")
    ap.add_argument("--title", default=None, help="Report title (default: based on filename)")
    args = ap.parse_args(list(argv) if argv is not None else None)

    title = args.title
    if not title:
        title = f"Report: {os.path.basename(args.json_path)}"

    try:
        data = load_json(args.json_path)
        md = generate_markdown(data, title=title)
    except ReportError as e:
        print(f"ERROR: {e}", file=sys.stderr)
        return 2

    print(md)
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
